import React from 'react';

interface LinkCardProps {
    title: string;
    url: string;
    description?: string;
    onClick?: () => void;
}

const LinkCard: React.FC<LinkCardProps> = ({ title, url, description, onClick }) => {
    return (
        <div className="link-card" onClick={onClick}>
            <h3>{title}</h3>
            <p>{description}</p>
            <a href={url} target="_blank" rel="noopener noreferrer">
                {url}
            </a>
        </div>
    );
};

export default LinkCard;
